    var ADDS = [{"p":"PART 1. 일제의 식민 통치 정책 (무단→문화→민족말살)","q":[{"answer":"O","text":"1910년대 무단 통치 시기 일제는 회사를 설립할 때 조선 총독의 허가를 받도록 하는 회사령을 시행하여 조선인의 기업 활동을 억압하였다.","exp":"1910년 공포된 회사령은 회사 설립을 총독의 허가 사항으로 묶어 민족 자본의 성장을 막았다. 헌병 경찰제·조선 태형령과 함께 1910년대 무단 통치를 상징하는 정책으로, 신고제로 완화된 것은 1920년 문화 통치기이다.","src":"한능검 제75회"},{"answer":"X","text":"1910년대 무단 통치 시기 일제는 만주 지역 독립군을 탄압하기 위해 중국 군벌과 미쓰야 협정을 맺어 활동을 크게 위축시켰다.","exp":"미쓰야 협정은 1925년 문화 통치기에 조선 총독부 경무국장 미쓰야와 만주 군벌 사이에 맺어진 것이다. 회사령·조선 태형령이 시행되던 1910년대 무단 통치기의 정책으로 서술한 것은 시기가 맞지 않는다."}],"tb":[],"wi":["📝 \"1910년대 무단 통치기에 미쓰야 협정을 맺었다\" → ❌ 미쓰야 협정은 1925년 문화 통치기에 체결되었다."]},{"p":"PART 1. 일제의 식민 통치 정책 (무단→문화→민족말살)","q":[{"answer":"O","text":"민족 말살 통치 시기 일제는 애국반을 조직하여 한국인의 일상생활을 감시하고 전쟁에 협력하도록 강요하였다.","exp":"국가 총동원 체제 아래 일제는 최말단 통제 조직인 애국반을 두어 배급·공출·근로 동원을 강제하고 주민을 상호 감시하게 하였다. 금속류 회수령에 따른 놋그릇·사찰 종 공출과 함께 민족 말살 통치기 총동원 정책의 하나이다.","src":"한능검 제75회"},{"answer":"X","text":"1910년대 무단 통치 시기 일제는 애국반을 조직하여 한국인의 일상생활을 감시하고 전쟁에 협력하도록 강요하였다.","exp":"애국반은 중일 전쟁 이후 국가 총동원 체제가 강화된 민족 말살 통치기에 만들어진 통제 조직이다. 헌병 경찰제가 시행되던 1910년대 무단 통치 시기의 일로 서술한 것은 시기가 맞지 않는다."}],"tb":[{"k":"p","t":"민족 말살 통치기 일제는 전시 총동원을 위해 최말단 조직인 애국반을 두어 열 집 안팎을 하나로 묶었다. 애국반을 통해 배급과 공출을 관리하고 근로·저축을 강요하였으며 주민끼리 서로 감시하게 하였다. 금속류 회수령에 따른 놋그릇·사찰 종 공출도 이 무렵 이루어졌다."}],"wi":["📝 \"1910년대 무단 통치기에 애국반을 조직하여 주민을 통제하였다\" → ❌ 애국반은 민족 말살 통치기의 전시 총동원 조직이다."]},{"p":"PART 2. 3·1 운동과 대한민국 임시 정부·국외 독립운동 기지","q":[{"answer":"O","text":"멕시코로 이주한 한인들은 숭무 학교를 세워 독립군을 양성하며 무장 투쟁을 준비하였다.","exp":"1905년 유카탄 반도의 에네켄 농장으로 이주한 한인들은 열악한 환경 속에서도 숭무 학교를 세워 군사 교육을 실시하였다. 서간도 신흥 무관 학교, 하와이 대조선 국민 군단과 함께 국외 독립군 양성 기관으로 기억한다.","src":"한능검 제75회"},{"answer":"X","text":"멕시코로 이주한 한인들은 권업회를 조직하고 권업신문을 발행하며 무장 투쟁을 준비하였다.","exp":"권업회를 조직하고 권업신문을 발행한 곳은 연해주 신한촌이다. 멕시코 이주 한인들은 숭무 학교를 세워 독립군을 양성하였으므로 지역과 단체를 뒤바꾼 서술이다."}],"tb":[{"k":"p","t":"1905년 한인들은 멕시코 유카탄 반도의 에네켄(용설란) 농장으로 노동 이민을 떠났다. 가혹한 노동 속에서도 이들은 숭무 학교를 세워 독립군을 양성하는 등 국외에서 민족 운동을 이어 갔다."}],"wi":["📝 \"멕시코 이주 한인들이 권업회를 조직하고 권업신문을 발행하였다\" → ❌ 권업회·권업신문은 연해주 신한촌, 멕시코 한인은 숭무 학교를 세웠다."]},{"p":"PART 2. 3·1 운동과 대한민국 임시 정부·국외 독립운동 기지","q":[{"answer":"O","text":"대동단결 선언은 융희 황제가 주권을 포기한 날 국민이 그 주권을 이어받는다는 국민 주권론을 내세워 공화주의에 입각한 임시 정부 수립을 제창하였다.","exp":"1917년 신규식·조소앙 등이 발표한 대동단결 선언은 순종의 주권 포기를 국민에게 주권이 넘어온 계기로 해석하여 국민 주권론과 공화제 임시 정부 수립을 주장하였다. 2년 뒤 수립되는 대한민국 임시 정부의 이념적 토대가 되었다.","src":"한능검 제75회"},{"answer":"X","text":"대동단결 선언은 융희 황제를 다시 황제로 세워 대한 제국을 회복하려는 복벽주의를 내세워 발표되었다.","exp":"대동단결 선언은 황제의 주권 포기를 국민 주권 계승의 근거로 삼은 공화주의 선언이다. 고종·순종을 다시 세우려는 복벽주의는 독립 의군부 등의 노선으로, 선언의 국민 주권론과는 정반대이다."}],"tb":[{"k":"p","t":"1917년 상하이에서 신규식·조소앙 등 14인이 발표한 대동단결 선언은 융희 황제(순종)가 주권을 포기한 순간 그 주권이 국민에게 넘어왔다는 국민 주권론을 내세웠다. 이를 근거로 공화주의에 바탕을 둔 임시 정부 수립을 제창하여 대한민국 임시 정부의 이론적 밑바탕이 되었다."}],"wi":["📝 \"대동단결 선언은 고종을 다시 세우려는 복벽주의를 내세웠다\" → ❌ 대동단결 선언은 국민 주권론에 입각한 공화주의 임시 정부 수립을 제창하였다."]},{"p":"PART 2. 3·1 운동과 대한민국 임시 정부·국외 독립운동 기지","q":[{"answer":"O","text":"3·1 운동은 미국 대통령 윌슨이 제창한 민족 자결주의의 영향을 받아 일어난 일제 강점기 최대 규모의 독립운동이다.","exp":"윌슨의 민족 자결주의와 도쿄 유학생의 2·8 독립 선언이 도화선이 되어 1919년 3·1 운동이 전국으로 확산되었다. 대한민국 임시 정부 수립과 일제의 이른바 문화 통치 전환을 이끈 최대 규모의 만세 운동이다.","src":"한능검 제75회"}],"tb":[],"wi":[]},{"p":"PART 4. 무장 독립 투쟁 (의열단·의거·독립군·광복군)","q":[{"answer":"O","text":"한국 광복군은 미국 전략 정보국(OSS)과 연계하여 국내 진공 작전을 준비하였으나 일제의 항복으로 실행하지 못하였다.","exp":"충칭 임시 정부의 한국 광복군은 미국 OSS와 합동으로 특수 훈련을 받고 국내 정진군을 편성해 진공 작전을 준비하였다. 그러나 작전 개시 직전 일제가 항복하여 뜻을 이루지 못하였다.","src":"한능검 제75회"},{"answer":"X","text":"조선 의용대는 미국 전략 정보국(OSS)과 연계하여 국내 진공 작전을 준비하였으나 일제의 항복으로 실행하지 못하였다.","exp":"미국 OSS와 함께 국내 진공 작전을 준비한 부대는 한국 광복군이다. 조선 의용대는 김원봉이 중국 우한에서 창설한 중국 관내 최초의 한인 무장 부대로, 두 부대의 활동을 뒤바꾼 서술이다."}],"tb":[],"wi":["📝 \"조선 의용대가 미국 OSS와 국내 진공 작전을 준비하였다\" → ❌ OSS와 국내 진공 작전을 준비한 부대는 한국 광복군이다."]},{"p":"PART 5. 민족 문화 수호 운동과 사회·문화","q":[{"answer":"O","text":"1920년대에는 경성 제국 대학에 입학하여 공부하는 조선인 학생의 모습을 볼 수 있었다.","exp":"일제는 민립 대학 설립 운동을 무마하기 위해 1924년 관립 경성 제국 대학을 세웠다. 을축년 대홍수·관동 대지진 무렵인 1920년대의 모습으로, 조선인의 고등 교육 기회는 매우 제한적이었다.","src":"한능검 제75회"},{"answer":"X","text":"1920년대에는 육영 공원에서 미국인 교사에게 영어를 배우는 학생의 모습을 볼 수 있었다.","exp":"육영 공원은 1886년 개항기에 세워진 근대식 관립 학교로 헐버트 등 미국인 교사가 상류층 자제를 가르쳤다. 경성 제국 대학이 세워진 1920년대와는 시기가 전혀 다른 개항기의 모습이다."}],"tb":[{"k":"p","t":"일제는 실력 양성 운동으로 전개된 민립 대학 설립 운동을 무마하려 1924년 관립 경성 제국 대학을 세웠다. 조선인에게 열린 유일한 대학이었으나 입학은 극히 제한적이었고, 1920년대 근대 교육의 한 단면을 보여 준다."}],"wi":["📝 \"1920년대에 육영 공원에서 영어를 배우는 학생을 볼 수 있었다\" → ❌ 육영 공원(1886)은 개항기 학교, 1920년대에는 경성 제국 대학(1924)이 있었다."]},{"p":"PART 5. 민족 문화 수호 운동과 사회·문화","q":[{"answer":"O","text":"일제 강점기에는 나운규가 제작한 영화 아리랑이 상영되어 민족의 애환을 담아 큰 호응을 얻었다.","exp":"1926년 개봉한 나운규의 아리랑은 나라 잃은 민족의 정서를 담아 폭발적 인기를 끌었다. 미쓰코시 백화점·모던 걸·모던 보이로 대표되는 1920년대 근대 대중문화 확산의 한 장면이다.","src":"한능검 제75회"},{"answer":"X","text":"일제 강점기에는 극장에서 나운규의 영화 아리랑을 관람하고 잡지 사상계를 사서 읽는 사람들의 모습을 볼 수 있었다.","exp":"영화 아리랑은 1926년 일제 강점기에 상영된 것이 맞지만, 잡지 사상계는 광복 후인 1953년에 창간되었다. 서로 다른 시대의 문화를 한데 묶어 서술한 오답이다."}],"tb":[],"wi":["📝 \"일제 강점기에 잡지 사상계를 사서 읽는 모습을 볼 수 있었다\" → ❌ 사상계는 1953년 창간된 현대의 잡지이다."]}];
