    var ADDS = [{"p":"PART 3. 국내 민족 운동 (실력 양성·사회·학생·신간회)","q":[{"answer":"O","text":"천도교 소년회는 김기전·방정환 등을 중심으로 5월 1일을 어린이날로 정하고 잡지 '어린이'를 발간하는 등 소년 운동을 전개하였다.","exp":"어린이날 제정과 잡지 '어린이' 발간을 이끈 소년 운동의 중심은 천도교 소년회이다. 방정환은 이 단체를 이끈 인물로, 신간회·근우회 등 다른 사회단체와 혼동하지 않도록 한다.","src":"한능검 제73회"},{"answer":"X","text":"조선어 학회는 김기전·방정환 등을 중심으로 5월 1일을 어린이날로 정하고 잡지 '어린이'를 발간하는 등 소년 운동을 전개하였다.","exp":"어린이날 제정과 잡지 '어린이' 발간을 통한 소년 운동은 천도교 소년회가 전개한 것이므로 조선어 학회의 활동으로 볼 수 없다. 조선어 학회는 한글 맞춤법 통일안·표준어 제정과 우리말 큰사전 편찬을 추진하였다."}],"tb":[],"wi":["📝 \"어린이날 제정·잡지 어린이 발간을 조선어 학회가 하였다\" → ❌ 소년 운동은 천도교 소년회(방정환) (조선어 학회는 한글 맞춤법 통일안·큰사전 편찬)"]},{"p":"PART 3. 국내 민족 운동 (실력 양성·사회·학생·신간회)","q":[{"answer":"X","text":"대공황 이후 일제가 농촌 진흥 운동과 남면북양 정책을 펴던 1930년대에는 여성의 지위 향상을 내세운 근우회가 창립 총회를 열고 활동을 시작하였다.","exp":"근우회는 1927년 신간회의 자매단체로 창립되었으므로 대공황 이후 1930년대에 창립 총회를 열었다는 서술은 시기가 맞지 않는다. 농촌 진흥 운동·남면북양 정책이 추진되던 1930년대에는 혁명적 농민 조합이 결성되어 일제에 저항하였다."},{"answer":"O","text":"대공황 이후 일제가 농촌 진흥 운동과 남면북양 정책을 펴던 1930년대에는 혁명적 농민 조합이 결성되어 소작료 인하 등을 내세우며 일제에 저항하였다.","exp":"1930년대 대공황기에는 사회주의 세력과 연계된 혁명적 농민 조합이 결성되어 소작료 인하 등을 내세우며 비합법 투쟁을 벌였다. 합법적 실력 양성을 지향한 1920년대 소작 쟁의와 성격이 달라진 점을 구분한다.","src":"한능검 제73회"}],"tb":[{"k":"p","t":"대공황 이후 1930년대에는 사회주의 세력과 연계된 혁명적 농민 조합·혁명적 노동 조합이 결성되어 소작료 인하와 노동 조건 개선 등을 내세우며 비합법적 저항 운동을 전개하였다."}],"wi":["📝 \"1930년대 대공황기에 근우회가 창립되었다\" → ❌ 근우회 창립은 1927년 (1930년대에는 혁명적 농민·노동 조합이 결성되어 저항)"]}];
